201→func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
202→	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
203→	if emailAddress == "" {
204→		return nil
205→	}
206→	domain := ""
207→	parts := strings.SplitN(emailAddress, "@", 2)
208→	if len(parts) == 2 {
209→		domain = parts[1]
210→	}
211→
212→	_, err := d.Exec(`
213→		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
214→		VALUES (?, ?, ?, ?, ?, 1, ?)
215→		ON CONFLICT(source, email) DO UPDATE SET
216→			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
217→			last_activity_at = CASE
218→				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
219→				ELSE contacts.last_activity_at
220→			END,
221→			last_emailed_at = CASE
222→				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
223→				ELSE contacts.last_emailed_at
224→			END,
225→			email_count = contacts.email_count + ?,
226→			updated_at = datetime('now')`,
227→		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
228→	)
229→	return err
230→}
231→
232→func boolToInt(value bool) int {
233→	if value {
234→		return 1
235→	}
236→	return 0
237→}
238→
239→func extractEmail(header string) string {
240→	if i := strings.Index(header, "<"); i != -1 {
241→		if j := strings.Index(header, ">"); j != -1 {
242→			return header[i+1 : j]
243→		}
244→	}
245→	return strings.TrimSpace(header)
246→}
247→
248→func emailsToJSON(header string) string {
249→	if header == "" {
250→		return "[]"
251→	}
252→	parts := strings.Split(header, ",")
253→	emails := make([]string, 0, len(parts))
254→	for _, p := range parts {
255→		emails = append(emails, extractEmail(p))
256→	}
257→	data, _ := json.Marshal(emails)
258→	return string(data)
259→}
