331→
332→// loadSyncState reads the sync cursor from a local config-like store.
333→func (e *Engine) loadSyncState() (*SyncState, error) {
334→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
335→	var data string
336→	err := e.db.QueryRow(
337→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
338→	).Scan(&data)
339→	if err == sql.ErrNoRows {
340→		return &SyncState{}, nil
341→	}
342→	if err != nil {
343→		return nil, err
344→	}
345→
346→	var state SyncState
347→	if err := json.Unmarshal([]byte(data), &state); err != nil {
348→		return &SyncState{}, nil
349→	}
350→	return &state, nil
351→}
