353→// saveSyncState persists the sync cursor.
354→func (e *Engine) saveSyncState(state *SyncState) error {
355→	data, err := json.Marshal(state)
356→	if err != nil {
357→		return err
358→	}
359→
360→	_, err = e.db.Exec(`
361→		INSERT INTO connectors (id, type, sync_cursor)
362→		VALUES (?, 'sync', ?)
363→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
364→		syncStateKey, string(data),
365→	)
366→	return err
367→}
