  1→package automation
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"runtime"
  8→	"strings"
  9→)
 10→
 11→const (
 12→	dispatcherScriptRelativePath = ".nurge/bin/dispatcher-run.sh"
 13→	dispatcherLogRelativePath    = ".nurge/logs/dispatcher.log"
 14→	dispatcherPlistRelativePath  = ".nurge/automation/dispatcher.plist"
 15→)
 16→
 17→// DispatcherOptions configures the generated unattended wrapper.
 18→type DispatcherOptions struct {
 19→	ProjectRoot     string
 20→	ExecutablePath  string
 21→	IntervalMinutes int
 22→	SyncReplies     bool
 23→	TransportEmail  string
 24→}
 25→
 26→// DispatcherAssets describes the generated unattended runner assets.
 27→type DispatcherAssets struct {
 28→	ProjectRoot        string `json:"project_root"`
 29→	ScriptPath         string `json:"script_path"`
 30→	LogPath            string `json:"log_path"`
 31→	CronLine           string `json:"cron_line,omitempty"`
 32→	LaunchdLabel       string `json:"launchd_label"`
 33→	LaunchdPlistPath   string `json:"launchd_plist_path"`
 34→	LaunchdInstallPath string `json:"launchd_install_path,omitempty"`
 35→	IntervalMinutes    int    `json:"interval_minutes"`
 36→	SyncReplies        bool   `json:"sync_replies"`
 37→	TransportEmail     string `json:"transport_email,omitempty"`
 38→}
 39→
 40→// WriteDispatcherAssets writes a local unattended wrapper script plus the
 41→// companion launchd plist that can be copied into LaunchAgents on macOS.
 42→func WriteDispatcherAssets(opts DispatcherOptions) (*DispatcherAssets, error) {
 43→	if strings.TrimSpace(opts.ProjectRoot) == "" {
 44→		return nil, fmt.Errorf("project root is required")
 45→	}
 46→	if strings.TrimSpace(opts.ExecutablePath) == "" {
 47→		return nil, fmt.Errorf("executable path is required")
 48→	}
 49→	if opts.IntervalMinutes <= 0 {
 50→		opts.IntervalMinutes = 5
 51→	}
 52→
 53→	projectRoot, err := filepath.Abs(opts.ProjectRoot)
 54→	if err != nil {
 55→		return nil, fmt.Errorf("resolving project root: %w", err)
 56→	}
 57→	executablePath, err := filepath.Abs(opts.ExecutablePath)
 58→	if err != nil {
 59→		return nil, fmt.Errorf("resolving executable path: %w", err)
 60→	}
 61→
 62→	scriptPath := filepath.Join(projectRoot, dispatcherScriptRelativePath)
 63→	logPath := filepath.Join(projectRoot, dispatcherLogRelativePath)
 64→	plistPath := filepath.Join(projectRoot, dispatcherPlistRelativePath)
 65→
 66→	if err := os.MkdirAll(filepath.Dir(scriptPath), 0755); err != nil {
 67→		return nil, fmt.Errorf("creating wrapper directory: %w", err)
 68→	}
 69→	if err := os.MkdirAll(filepath.Dir(logPath), 0755); err != nil {
 70→		return nil, fmt.Errorf("creating log directory: %w", err)
 71→	}
 72→	if err := os.MkdirAll(filepath.Dir(plistPath), 0755); err != nil {
 73→		return nil, fmt.Errorf("creating automation directory: %w", err)
 74→	}
 75→
 76→	script, err := BuildDispatcherScript(projectRoot, executablePath, DispatcherOptions{
 77→		ProjectRoot:     projectRoot,
 78→		ExecutablePath:  executablePath,
 79→		IntervalMinutes: opts.IntervalMinutes,
 80→		SyncReplies:     opts.SyncReplies,
 81→		TransportEmail:  opts.TransportEmail,
 82→	})
 83→	if err != nil {
 84→		return nil, err
 85→	}
 86→	if err := os.WriteFile(scriptPath, []byte(script), 0755); err != nil {
 87→		return nil, fmt.Errorf("writing wrapper script: %w", err)
 88→	}
 89→
 90→	label := launchdLabel(projectRoot)
 91→	plist := BuildLaunchdPlist(label, projectRoot, scriptPath, logPath, opts.IntervalMinutes)
 92→	if err := os.WriteFile(plistPath, []byte(plist), 0644); err != nil {
 93→		return nil, fmt.Errorf("writing launchd plist: %w", err)
 94→	}
 95→
 96→	cronLine, _ := CronLine(scriptPath, opts.IntervalMinutes)
 97→
 98→	assets := &DispatcherAssets{
 99→		ProjectRoot:      projectRoot,
100→		ScriptPath:       scriptPath,
101→		LogPath:          logPath,
102→		CronLine:         cronLine,
103→		LaunchdLabel:     label,
104→		LaunchdPlistPath: plistPath,
105→		IntervalMinutes:  opts.IntervalMinutes,
106→		SyncReplies:      opts.SyncReplies,
107→		TransportEmail:   strings.TrimSpace(opts.TransportEmail),
108→	}
109→
110→	if runtime.GOOS == "darwin" {
111→		if home, err := os.UserHomeDir(); err == nil {
112→			assets.LaunchdInstallPath = filepath.Join(home, "Library", "LaunchAgents", label+".plist")
113→		}
114→	}
115→
116→	return assets, nil
117→}
118→
119→// BuildDispatcherScript renders a shell wrapper that always runs from the
120→// project root and appends output to the project's dispatcher log.
121→func BuildDispatcherScript(projectRoot, executablePath string, opts DispatcherOptions) (string, error) {
122→	projectRoot = strings.TrimSpace(projectRoot)
123→	executablePath = strings.TrimSpace(executablePath)
124→	if projectRoot == "" {
125→		return "", fmt.Errorf("project root is required")
126→	}
127→	if executablePath == "" {
128→		return "", fmt.Errorf("executable path is required")
129→	}
130→
131→	logPath := filepath.Join(projectRoot, dispatcherLogRelativePath)
132→
133→	args := []string{
134→		shellQuote(executablePath),
135→		"dispatcher",
136→		"run",
137→		"--execute",
138→		fmt.Sprintf("--sync-replies=%t", opts.SyncReplies),
139→	}
140→	if transport := strings.TrimSpace(opts.TransportEmail); transport != "" {
141→		args = append(args, "--transport-email", shellQuote(transport))
142→	}
143→
144→	script := strings.Join([]string{
145→		"#!/bin/sh",
146→		"set -eu",
147→		"",
148→		"PROJECT_ROOT=" + shellQuote(projectRoot),
149→		"LOG_PATH=" + shellQuote(logPath),
150→		"",
151→		"mkdir -p \"$(dirname \"$LOG_PATH\")\"",
152→		"cd \"$PROJECT_ROOT\"",
153→		"exec " + strings.Join(args, " ") + " >>\"$LOG_PATH\" 2>&1",
154→		"",
155→	}, "\n")
156→
157→	return script, nil
158→}
159→
160→// CronLine returns a crontab entry for the generated wrapper when the
161→// requested interval maps cleanly to standard cron syntax.
162→func CronLine(scriptPath string, intervalMinutes int) (string, bool) {
163→	spec, ok := cronExpression(intervalMinutes)
164→	if !ok {
165→		return "", false
166→	}
167→	return spec + " " + shellQuote(scriptPath), true
168→}
169→
170→func cronExpression(intervalMinutes int) (string, bool) {
171→	if intervalMinutes <= 0 {
172→		return "", false
173→	}
174→	if intervalMinutes == 1 {
175→		return "* * * * *", true
176→	}
177→	if intervalMinutes < 60 {
178→		if 60%intervalMinutes != 0 {
179→			return "", false
180→		}
181→		return fmt.Sprintf("*/%d * * * *", intervalMinutes), true
182→	}
183→	if intervalMinutes == 60 {
184→		return "0 * * * *", true
185→	}
186→	if intervalMinutes < 24*60 && intervalMinutes%60 == 0 {
187→		hours := intervalMinutes / 60
188→		if 24%hours != 0 {
189→			return "", false
190→		}
191→		return fmt.Sprintf("0 */%d * * *", hours), true
192→	}
193→	if intervalMinutes == 24*60 {
194→		return "0 0 * * *", true
195→	}
196→	return "", false
197→}
198→
199→// BuildLaunchdPlist renders a launchd agent definition that runs the
200→// generated wrapper on a fixed interval.
201→func BuildLaunchdPlist(label, projectRoot, scriptPath, logPath string, intervalMinutes int) string {
202→	if intervalMinutes <= 0 {
203→		intervalMinutes = 5
204→	}
205→	startIntervalSeconds := intervalMinutes * 60
206→
207→	lines := []string{
208→		`<?xml version="1.0" encoding="UTF-8"?>`,
209→		`<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">`,
210→		`<plist version="1.0">`,
211→		`<dict>`,
212→		`  <key>Label</key>`,
213→		`  <string>` + xmlEscape(label) + `</string>`,
214→		`  <key>ProgramArguments</key>`,
215→		`  <array>`,
216→		`    <string>` + xmlEscape(scriptPath) + `</string>`,
217→		`  </array>`,
218→		`  <key>WorkingDirectory</key>`,
219→		`  <string>` + xmlEscape(projectRoot) + `</string>`,
220→		`  <key>RunAtLoad</key>`,
221→		`  <true/>`,
222→		`  <key>StartInterval</key>`,
223→		fmt.Sprintf("  <integer>%d</integer>", startIntervalSeconds),
224→		`  <key>StandardOutPath</key>`,
225→		`  <string>` + xmlEscape(logPath) + `</string>`,
226→		`  <key>StandardErrorPath</key>`,
227→		`  <string>` + xmlEscape(logPath) + `</string>`,
228→		`</dict>`,
229→		`</plist>`,
230→		"",
231→	}
232→
233→	return strings.Join(lines, "\n")
234→}
235→
236→func launchdLabel(projectRoot string) string {
237→	base := strings.ToLower(filepath.Base(projectRoot))
238→	base = strings.Map(func(r rune) rune {
239→		switch {
240→		case r >= 'a' && r <= 'z':
241→			return r
242→		case r >= '0' && r <= '9':
243→			return r
244→		default:
245→			return '-'
246→		}
247→	}, base)
248→	base = strings.Trim(base, "-")
249→	for strings.Contains(base, "--") {
250→		base = strings.ReplaceAll(base, "--", "-")
251→	}
252→	if base == "" {
253→		base = "project"
254→	}
255→	return "com.usenurge.dispatcher." + base
256→}
257→
258→func shellQuote(value string) string {
259→	if value == "" {
260→		return "''"
261→	}
262→	return "'" + strings.ReplaceAll(value, "'", `'"'"'`) + "'"
263→}
264→
265→func xmlEscape(value string) string {
266→	replacer := strings.NewReplacer(
267→		"&", "&amp;",
268→		"<", "&lt;",
269→		">", "&gt;",
270→		`"`, "&quot;",
271→		"'", "&apos;",
272→	)
273→	return replacer.Replace(value)
274→}
