 51→func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 52→	var oauthCfg *oauth2.Config
 53→	var authOpts []oauth2.AuthCodeOption
 54→
 55→	if g.def.Credentials.Source == "google_json" {
 56→		// Google-specific: use google.ConfigFromJSON
 57→		credsData, err := g.loadGoogleCredentials()
 58→		if err != nil {
 59→			return nil, err
 60→		}
 61→		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 62→		if err != nil {
 63→			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 64→		}
 65→		oauthCfg = cfg
 66→	} else {
 67→		// Generic OAuth2: build config from YAML
 68→		clientID, clientSecret, err := g.resolveOAuthCredentials()
 69→		if err != nil {
 70→			return nil, err
 71→		}
 72→		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 73→		if err != nil {
 74→			return nil, err
 75→		}
 76→		oauthCfg = cfg
 77→		authOpts = opts
 78→	}
 79→
 80→	// Add extra_params as auth options for google_json too
 81→	if g.def.Credentials.Source == "google_json" {
 82→		for k, v := range g.def.Auth.ExtraParams {
 83→			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 84→		}
 85→	}
 86→
 87→	// Run shared OAuth flow
 88→	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 89→	if err != nil {
 90→		return nil, err
 91→	}
 92→
 93→	// Save token
 94→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 95→	tokenPath := tokenDir + "/token.json"
 96→	if err := os.MkdirAll(tokenDir, 0755); err != nil {
 97→		return nil, fmt.Errorf("creating connector dir: %w", err)
 98→	}
 99→	if err := saveToken(tokenPath, token); err != nil {
100→		return nil, fmt.Errorf("saving token: %w", err)
101→	}
102→
103→	// Verify connection + get account identifier
104→	account, err := g.runVerify(ctx, oauthCfg, token)
105→	if err != nil {
106→		// Non-fatal: connected but can't verify
107→		account = "connected (unverified)"
108→	}
109→
110→	return &Result{
111→		Account: account,
112→		Token:   token,
113→	}, nil
114→}
