226→// resolveOAuthCredentials reads client ID and secret from the configured source.
227→func (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
228→	cred := g.def.Credentials
229→
230→	switch cred.Source {
231→	case "env":
232→		id := os.Getenv(cred.ClientIDVar)
233→		secret := os.Getenv(cred.ClientSecretVar)
234→		if id == "" || secret == "" {
235→			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
236→				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
237→		}
238→		return id, secret, nil
239→
240→	case "prompt":
241→		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
242→			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
243→		}
244→		var id, secret string
245→		fmt.Printf("Enter %s client ID: ", g.def.Name)
246→		fmt.Scanln(&id)
247→		fmt.Printf("Enter %s client secret: ", g.def.Name)
248→		fmt.Scanln(&secret)
249→		if id == "" || secret == "" {
250→			return "", "", fmt.Errorf("client ID and secret are required")
251→		}
252→		return id, secret, nil
253→
254→	default:
255→		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
256→	}
257→}
