 21→func SyncReplies(srv *gm.Service, d *sql.DB, mailboxEmail string, now time.Time) (*ReplySyncResult, error) {
 22→	if now.IsZero() {
 23→		now = time.Now()
 24→	}
 25→
 26→	enrollments, err := sequence.ListEnrollments(d, sequence.StatusActive, 0)
 27→	if err != nil {
 28→		return nil, err
 29→	}
 30→
 31→	result := &ReplySyncResult{}
 32→	for _, enrollment := range enrollments {
 33→		if enrollment.ThreadID == "" {
 34→			continue
 35→		}
 36→		if mailboxEmail != "" && !strings.EqualFold(mailboxEmail, enrollment.MailboxEmail) {
 37→			continue
 38→		}
 39→
 40→		thread, err := srv.Users.Threads.Get("me", enrollment.ThreadID).Format("metadata").
 41→			MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 42→		if err != nil {
 43→			return nil, err
 44→		}
 45→		result.ThreadsScanned++
 46→
 47→		watermark := latestKnownThreadTime(enrollment)
 48→		for i := 0; i < len(thread.Messages); i++ {
 49→			result.MessagesScanned++
